import xml.etree.ElementTree as ET
from datetime import datetime
from django.contrib.auth.models import User
from django.contrib.sessions.models import Session
from saml2 import client, BINDING_HTTP_POST
from saml2.samlp import NAMEID_FORMAT_TRANSIENT

class SAMLServiceProvider:
    def __init__(self, settings):
        self.settings = settings
        self.entity_id = settings.SAML_ENTITY_ID
        self.idp_entity_id = settings.SAML_IDP_ENTITY_ID
        self.binding = BINDING_HTTP_POST

    def parse_saml_assertion(self, saml_response):
        try:
            tree = ET.fromstring(saml_response)
        except ET.ParseError as e:
            return None, str(e)

        assertion = tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
        if not assertion:
            return None, 'No Assertion found in SAML response'

        issuer = assertion.find('{urn:oasis:names:tc:SAML:2.0:assertion}Issuer').text
        if issuer != self.idp_entity_id:
            return None, 'Invalid Issuer in SAML response'

        nameid = assertion.find('{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        if not nameid:
            return None, 'No NameID found in SAML response'
        nameid_value = nameid.text
        if not nameid_value:
            return None, 'Empty NameID value'

        attributes = {}
        for attribute in assertion.findall('{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attribute.find('{urn:oasis:names:tc:SAML:2.0:assertion}Name').text
            attr_value = attribute.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')
            if attr_value is not None:
                attributes[attr_name] = attr_value.text

        return nameid_value, attributes

    def validate_saml_timestamp(self, saml_response):
        try:
            tree = ET.fromstring(saml_response)
        except ET.ParseError as e:
            return False, str(e)

        assertion = tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
        if not assertion:
            return False, 'No Assertion found in SAML response'

        issued_at = datetime.strptime(assertion.attrib['IssueInstant'], '%Y-%m-%dT%H:%M:%SZ')
        current_time = datetime.now()
        if (current_time - issued_at).total_seconds() > 300:  # 5 minutes
            return False, 'SAML assertion timestamp is invalid'

        return True, ''

    def create_django_user(self, nameid_value, attributes):
        user_data = {
            'username': nameid_value,
            'email': attributes.get('mail', ''),
            'first_name': attributes.get('givenName', ''),
            'last_name': attributes.get('sn', '')
        }

        try:
            user = User.objects.create_user(**user_data)
        except Exception as e:
            return None, str(e)

        session_key = self.settings.SESSION_COOKIE_NAME
        session = Session.objects.create(session_key=session_key, expire_date=datetime.now() + datetime.timedelta(days=30))
        session.data['username'] = nameid_value
        session.save()

        return user, ''

    def handle_saml_post(self, saml_response):
        nameid_value, attributes = self.parse_saml_assertion(saml_response)
        if not nameid_value:
            return None

        is_valid_timestamp, error_message = self.validate_saml_timestamp(saml_response)
        if not is_valid_timestamp:
            return None, error_message

        user, error_message = self.create_django_user(nameid_value, attributes)
        if not user:
            return None, error_message

        return user